import Swal from "sweetalert2";

export function mostralAlerta(simbolo, titulo, mensaje) {
  Swal.fire({
    title: titulo,
    text: mensaje,
    icon: simbolo,
    confirmButtonText: "Aceptar",
    customClass: { confirmButton: "principales", popup: "alertStyle" },
  });
}

export function mostrarConfirmacion(simbolo, titulo, mensaje) {
  Swal.fire({
    showCancelButton: true,
    cancelButtonText: "cancelar",
    confirmButtonText: "Aceptar",
    icon: simbolo,
    title: titulo,
    text: mensaje,
    customClass: {
      popup: "alertStyle",
      confirmButton: "principales",
      cancelButton: "secundarios",
    },
  }).then();
}
